module arithmetic_shift_register (
    input clk,
    input load,
    input shift,
    input [7:0] data_in,
    output [7:0] q );reg [7:0] invalid_reg;

always @(posedge clk) begin
    if (load)
        invalid_reg <= data_in;
    else if (shift)
        invalid_reg <= {invalid_reg[6:0], 1'b0};
end

assign q = invalid_reg;

endmodule
